compliant:
#include <cstring>
#include <string>

class NonTrivial {
  std::string str;
public:
  NonTrivial(const std::string& s) : str(s) {}
  NonTrivial(const NonTrivial& other) = default; // Use copy constructor
  NonTrivial& operator=(const NonTrivial& other) = default;
};

void goodCopy() {
  NonTrivial obj1("hello");
  NonTrivial obj2 = obj1; // Compliant: proper copy
}

#include <cstring>

struct TrivialStruct {
  int a;
  char b;
  double c;
};

void copyTrivial() {
  TrivialStruct obj1{1, 'x', 3.14};
  TrivialStruct obj2;
  memcpy(&obj2, &obj1, sizeof(TrivialStruct)); // Compliant: trivially copyable
}

#include <cstring>

void copyPrimitives() {
  int arr1[10] = {0};
  int arr2[10];
  memcpy(arr2, arr1, sizeof(arr1)); // Compliant: primitive type array

  char buffer[256];
  memset(buffer, 0, sizeof(buffer)); // Compliant: primitive type
}
